    # -- helpers ----------------------------------------------------------
    def _validate_column(self, column: str) -> str:
        if column not in self.schema["columns"]:
            raise ValueError(
                f"Column '{column}' is not searchable in table '{self.table}'."
            )
        # Return the identifier safely quoted via psycopg2
        return psycopg2.extensions.quote_ident(column, None) if hasattr(psycopg2.extensions, 'quote_ident') else f'"{column}"'

    @staticmethod
    def _quote_ident(name: str) -> str:
        """Simple identifier quoting – only allows [a-zA-Z0-9_]."""
