    def select(self, columns: list[str]) -> "SafeSearchQueryBuilder":
        validated = [self._quote_ident(c) for c in columns if c in self.schema["columns"]]
        if validated:
            self._select_columns = validated
        return self

    def where(self, column: str, operator: str, value=None) -> "SafeSearchQueryBuilder":
        if column not in self.schema["columns"]:
            raise ValueError(f"Column '{column}' not allowed for table '{self.table}'.")
        if operator not in VALID_OPERATORS:
            raise ValueError(f"Operator '{operator}' is not supported.")

        col_ident = self._quote_ident(column)
        sql_op = VALID_OPERATORS[operator]

        if operator in ("is_null", "is_not_null"):
            self.conditions.append(f"{col_ident} {sql_op}")
        elif operator == "in":
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise ValueError("Operator 'in' requires a non-empty list.")
            placeholders = ", ".join(["%s"] * len(value))
            self.conditions.append(f"{col_ident} IN ({placeholders})")
            self.params.extend(value)
        else:
            self.conditions.append(f"{col_ident} {sql_op} %s")
            self.params.append(value)
        return self

    def full_text_search(self, query: str, columns: list[str] | None = None) -> "SafeSearchQueryBuilder":
        """Add a full-text / ILIKE search across multiple text columns."""
        target_cols = columns or list(self.schema["text_columns"])
        or_parts = []
        for col in target_cols:
            if col not in self.schema["text_columns"]:
                continue
            col_ident = self._quote_ident(col)
            or_parts.append(f"{col_ident} ILIKE %s")
            self.params.append(f"%{query}%")
        if or_parts:
            self.conditions.append(f"({' OR '.join(or_parts)})")
        return self

    def postgres_fts(self, query: str, columns: list[str] | None = None, language: str = "english") -> "SafeSearchQueryBuilder":
        """Use PostgreSQL full-text search with to_tsvector / plainto_tsquery."""
        target_cols = columns or list(self.schema["text_columns"])
        validated = [self._quote_ident(c) for c in target_cols if c in self.schema["text_columns"]]
        if not validated:
            return self
        # Concatenate columns: to_tsvector('english', coalesce(col1,'') || ' ' || coalesce(col2,''))
        concat_expr = " || ' ' || ".join(f"COALESCE({c}, '')" for c in validated)
        self.conditions.append(
            f"to_tsvector(%s, {concat_expr}) @@ plainto_tsquery(%s, %s)"
        )
        self.params.extend([language, language, query])
        return self

    def order_by(self, column: str, direction: str = "asc") -> "SafeSearchQueryBuilder":
        if column not in self.schema["columns"]:
            raise ValueError(f"Column '{column}' not allowed for ordering.")
        direction = direction.lower()
        if direction not in VALID_SORT_DIRECTIONS:
            raise ValueError(f"Sort direction '{direction}' is invalid.")
        self.order_clauses.append(f"{self._quote_ident(column)} {direction.upper()}")
        return self

    def limit(self, n: int) -> "SafeSearchQueryBuilder":
        self._limit = max(1, min(n, 1000))  # cap at 1000
        return self

    def offset(self, n: int) -> "SafeSearchQueryBuilder":
        self._offset = max(0, n)
        return self

    def build(self) -> tuple[str, list]:
        cols = ", ".join(self._select_columns)
        table_ident = self._quote_ident(self.table)
        sql = f"SELECT {cols} FROM {table_ident}"

        if self.conditions:
            sql += " WHERE " + " AND ".join(self.conditions)
        if self.order_clauses:
            sql += " ORDER BY " + ", ".join(self.order_clauses)
        if self._limit is not None:
            sql += " LIMIT %s"
            self.params.append(self._limit)
        if self._offset is not None:
            sql += " OFFSET %s"
            self.params.append(self._offset)

        return sql, self.params

    def build_count(self) -> tuple[str, list]:
        table_ident = self._quote_ident(self.table)
        sql = f"SELECT COUNT(*) FROM {table_ident}"
        params = list(self.params)  # copy up to conditions only
