def execute_safe_search(table, filters, text_query, fts_query, fts_columns,
                        order_by_field, order_dir, limit, offset, use_fts):
    builder = SafeSearchQueryBuilder(table)

    # Apply filters
    if filters:
        for f in filters:
            builder.where(
                column=f["field"],
                operator=f.get("operator", "eq"),
                value=f.get("value"),
            )

    # Text search (ILIKE)
    if text_query:
        builder.full_text_search(text_query)

    # PostgreSQL full-text search
    if fts_query and use_fts:
        builder.postgres_fts(fts_query, columns=fts_columns)

    if order_by_field:
        builder.order_by(order_by_field, order_dir or "asc")

    builder.limit(limit or 25)
    builder.offset(offset or 0)

    sql, params = builder.build()

    with get_connection() as conn:
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            cur.execute(sql, params)
            rows = cur.fetchall()

            # Count query (rebuild without limit/offset)
            count_builder = SafeSearchQueryBuilder(table)
            if filters:
                for f in filters:
                    count_builder.where(f["field"], f.get("operator", "eq"), f.get("value"))
            if text_query:
                count_builder.full_text_search(text_query)
            if fts_query and use_fts:
                count_builder.postgres_fts(fts_query, columns=fts_columns)

            count_sql, count_params = count_builder.build_count()
            cur.execute(count_sql, count_params)
            total = cur.fetchone()["count"]

    return rows, total


