class SearchFilterInput(graphene.InputObjectType):
    field = graphene.String(required=True, description="Column name to filter on")
    operator = graphene.String(
        default_value="eq",
        description="Operator: eq, neq, gt, gte, lt, lte, like, ilike, in, is_null, is_not_null",
    )
    value = graphene.String(description="Value to compare (JSON-encoded for 'in' operator)")
    values = graphene.List(graphene.String, description="List of values for 'in' operator")


class SearchInput(graphene.InputObjectType):
    table = graphene.String(required=True, description="Table to search: users, products, orders")
    filters = graphene.List(SearchFilterInput, description="Field-level filters")
    text_query = graphene.String(description="Free-text search (ILIKE across text columns)")
    fts_query = graphene.String(description="PostgreSQL full-text search query")
    fts_columns = graphene.List(graphene.String, description="Columns for FTS (defaults to all text columns)")
    use_fts = graphene.Boolean(default_value=False, description="Use PG full-text search instead of ILIKE")
    order_by = graphene.String(description="Column to sort by")
    order_direction = graphene.String(default_value="asc", description="asc or desc")
    limit = graphene.Int(default_value=25)
    offset = graphene.Int(default_value=0)


