class Query(graphene.ObjectType):
    search = graphene.Field(
        SearchResultPage,
        input=SearchInput(required=True),
        description="Dynamic search across tables with filters, text search, and pagination.",
    )

    # Convenience typed endpoints
    search_users = graphene.List(
        UserResult,
        query=graphene.String(),
        status=graphene.String(),
        limit=graphene.Int(default_value=25),
        offset=graphene.Int(default_value=0),
    )

    search_products = graphene.List(
        ProductResult,
        query=graphene.String(),
        category=graphene.String(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        limit=graphene.Int(default_value=25),
        offset=graphene.Int(default_value=0),
    )

    def resolve_search(root, info, input):
        import json

        # Normalise filters – handle 'in' operator with values list
        filters = []
        if input.filters:
            for f in input.filters:
                filt = {"field": f.field, "operator": f.operator}
                if f.operator == "in":
                    filt["value"] = list(f.values) if f.values else json.loads(f.value)
                elif f.operator not in ("is_null", "is_not_null"):
                    filt["value"] = f.value
                filters.append(filt)

        rows, total = execute_safe_search(
            table=input.table,
            filters=filters,
            text_query=input.text_query,
            fts_query=input.fts_query,
            fts_columns=input.fts_columns,
            order_by_field=input.order_by,
            order_dir=input.order_direction,
            limit=input.limit,
            offset=input.offset,
            use_fts=input.use_fts,
        )

        records = [SearchResultRecord(data=dict(row)) for row in rows]
        return SearchResultPage(
            records=records,
            total_count=total,
            limit=input.limit,
            offset=input.offset,
            has_next_page=(input.offset + input.limit) < total,
        )

    def resolve_search_users(root, info, query=None, status=None, limit=25, offset=0):
        filters = []
        if status:
            filters.append({"field": "status", "operator": "eq", "value": status})

        rows, _ = execute_safe_search(
            table="users",
            filters=filters,
            text_query=query,
            fts_query=None,
            fts_columns=None,
            order_by_field="created_at",
            order_dir="desc",
            limit=limit,
            offset=offset,
            use_fts=False,
        )
        return [UserResult(**dict(r)) for r in rows]

    def resolve_search_products(root, info, query=None, category=None,
                                 min_price=None, max_price=None, limit=25, offset=0):
        filters = []
        if category:
            filters.append({"field": "category", "operator": "eq", "value": category})
        if min_price is not None:
            filters.append({"field": "price", "operator": "gte", "value": str(min_price)})
        if max_price is not None:
            filters.append({"field": "price", "operator": "lte", "value": str(max_price)})

        rows, _ = execute_safe_search(
            table="products",
            filters=filters,
            text_query=query,
            fts_query=None,
            fts_columns=None,
            order_by_field="created_at",
            order_dir="desc",
            limit=limit,
            offset=offset,
            use_fts=False,
        )
        return [ProductResult(**dict(r)) for r in rows]


