# DB setup helper (run once)
# ---------------------------------------------------------------------------
def setup_database():
    """Create sample tables and seed data for testing."""
    with get_connection() as conn:
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS users (
                    id SERIAL PRIMARY KEY,
                    username VARCHAR(100) NOT NULL,
                    email VARCHAR(255) NOT NULL,
                    full_name VARCHAR(255),
                    status VARCHAR(20) DEFAULT 'active',
                    created_at TIMESTAMP DEFAULT NOW()
                );

                CREATE TABLE IF NOT EXISTS products (
                    id SERIAL PRIMARY KEY,
                    name VARCHAR(255) NOT NULL,
                    description TEXT,
                    sku VARCHAR(50),
                    price NUMERIC(10,2),
                    category VARCHAR(100),
                    created_at TIMESTAMP DEFAULT NOW()
                );

                CREATE TABLE IF NOT EXISTS orders (
                    id SERIAL PRIMARY KEY,
                    user_id INTEGER REFERENCES users(id),
                    status VARCHAR(20) DEFAULT 'pending',
                    total NUMERIC(10,2),
                    created_at TIMESTAMP DEFAULT NOW()
                );

                -- Full-text search indexes for performance
                CREATE INDEX IF NOT EXISTS idx_users_fts
                    ON users USING GIN (
                        to_tsvector('english',
                            COALESCE(username, '') || ' ' ||
                            COALESCE(email, '') || ' ' ||
                            COALESCE(full_name, '')
                        )
                    );

                CREATE INDEX IF NOT EXISTS idx_products_fts
                    ON products USING GIN (
                        to_tsvector('english',
                            COALESCE(name, '') || ' ' ||
                            COALESCE(description, '') || ' ' ||
                            COALESCE(sku, '') || ' ' ||
                            COALESCE(category, '')
                        )
                    );

                -- Trigram indexes for ILIKE performance
                CREATE EXTENSION IF NOT EXISTS pg_trgm;

                CREATE INDEX IF NOT EXISTS idx_users_username_trgm
                    ON users USING GIN (username gin_trgm_ops);
                CREATE INDEX IF NOT EXISTS idx_users_email_trgm
                    ON users USING GIN (email gin_trgm_ops);
                CREATE INDEX IF NOT EXISTS idx_products_name_trgm
                    ON products USING GIN (name gin_trgm_ops);
                CREATE INDEX IF NOT EXISTS idx_products_description_trgm
                    ON products USING GIN (description gin_trgm_ops);
            """)

            # Seed sample data
            cur.execute("SELECT COUNT(*) FROM users")
            if cur.fetchone()[0] == 0:
                cur.execute("""
                    INSERT INTO users (username, email, full_name, status) VALUES
                    ('alice', 'alice@example.com', 'Alice Johnson', 'active'),
                    ('bob', 'bob@example.com', 'Bob Smith', 'active'),
                    ('charlie', 'charlie@example.com', 'Charlie Brown', 'inactive'),
                    ('diana', 'diana@example.com', 'Diana Prince', 'active');
                """)
                cur.execute("""
                    INSERT INTO products (name, description, sku, price, category) VALUES
                    ('Widget Pro', 'A professional-grade widget', 'WGT-001', 29.99, 'widgets'),
                    ('Gadget Plus', 'Enhanced gadget with extras', 'GDG-002', 49.99, 'gadgets'),
                    ('Super Gizmo', 'The ultimate gizmo experience', 'GZM-003', 99.99, 'gizmos'),
                    ('Basic Widget', 'Entry-level widget', 'WGT-004', 9.99, 'widgets');
                """)
                cur.execute("""
                    INSERT INTO orders (user_id, status, total) VALUES
                    (1, 'completed', 59.98),
                    (2, 'pending', 49.99),
                    (1, 'shipped', 99.99),
                    (3, 'cancelled', 9.99);
                """)

            conn.commit()


